mapper.select:
SELECT id, dict_type, item_code, item_name, sort_no, enabled, remark, created_at, updated_at, deleted FROM sys_dictionary_item WHERE deleted = 0
AND (dict_type LIKE CONCAT('%', #{keyword}, '%') OR item_code LIKE CONCAT('%', #{keyword}, '%') OR item_name LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY id DESC LIMIT #{size} OFFSET #{offset}

mapper.update:
UPDATE sys_dictionary_item
SET deleted = 1, updated_at = NOW()
WHERE id = #{id}
